1	type Cell = [number, number]; // [x, y]
2	
3	function countLiveNeighbors(cells: Cell[], [x, y]: Cell): number {
4	  return cells.filter(
5	    ([nx, ny]) =>
6	      !(nx === x && ny === y) &&
7	      Math.abs(nx - x) <= 1 &&
8	      Math.abs(ny - y) <= 1,
9	  ).length;
10	}
11	
12	function survives(liveNeighbors: number): boolean {
13	  return liveNeighbors === 2 || liveNeighbors === 3;
14	}
15	
16	function isAlive(cells: Cell[], [x, y]: Cell): boolean {
17	  return cells.some(([cx, cy]) => cx === x && cy === y);
18	}
19	
20	function candidateCells(cells: Cell[]): Cell[] {
21	  const candidates: Cell[] = [];
22	  for (const [x, y] of cells) {
23	    for (let dx = -1; dx <= 1; dx++) {
24	      for (let dy = -1; dy <= 1; dy++) {
25	        const candidate: Cell = [x + dx, y + dy];
26	        if (!isAlive(candidates, candidate)) {
27	          candidates.push(candidate);
28	        }
29	      }
30	    }
31	  }
32	  return candidates;
33	}
34	
35	/**
36	 * Computes the next generation of live cells from the current live cells,
37	 * applying Conway's rules.
38	 */
39	export function nextGeneration(cells: Cell[]): Cell[] {
40	  return candidateCells(cells).filter((cell) => {
41	    const liveNeighbors = countLiveNeighbors(cells, cell);
42	    if (isAlive(cells, cell)) {
43	      return survives(liveNeighbors);
44	    }
45	    return liveNeighbors === 3;
46	  });
47	}
