4	describe("Game of Life - Next Generation", () => {
5	  it("returns an empty array for an empty grid — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	
9	  it("a single live cell dies of underpopulation — [(0,0)] → []", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	
13	  it("two live cells each with one neighbor die of underpopulation — [(0,1),(1,1)] → []", () => {
14	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
15	  });
16	
17	  it("a live cell with 2 or 3 live neighbors survives — center (1,1) survives in the survival example", () => {
18	    // (1,1) is live with exactly 3 live neighbors: (0,1), (2,1), (1,2)
19	    const result = nextGeneration([[1, 1], [0, 1], [2, 1], [1, 2]]);
20	    expect(result).toContainEqual([1, 1]);
21	  });
22	
23	  it("a live cell with more than 3 live neighbors dies of overpopulation — center (1,1) dies in the overpopulation example", () => {
24	    // (1,1) is live with 4 live neighbors: (0,1), (2,1), (1,0), (1,2)
25	    const result = nextGeneration([[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]]);
